// Class component
class DataTable extends React.Component {
  componentDidMount() {
    this.subscription = dataSource.subscribe(this.handleUpdate);
    this.setState({ data: dataSource.getValue() });
  }
  componentWillUnmount() {
    this.subscription.unsubscribe();
  }
}

// Function component equivalent
function DataTable() {
  const [data, setData] = useState(() => dataSource.getValue());

  useEffect(() => {
    const sub = dataSource.subscribe(setData);
    return () => sub.unsubscribe(); // combined mount + unmount
  }, []); // empty array ≈ componentDidMount + componentWillUnmount

  return <table>{/* ... */}</table>;
}

// Class component
class UserCard extends React.Component {
  componentDidUpdate(prevProps) {
    if (prevProps.userId !== this.props.userId) {
      this.setState({ data: null });
      fetchUser(this.props.userId).then((d) => this.setState({ data: d }));
    }
  }
}

// Function component
function UserCard({ userId }) {
  const [data, setData] = useState(null);

  useEffect(() => {
    let cancelled = false;
    setData(null);
    fetchUser(userId).then((d) => { if (!cancelled) setData(d); });
    return () => { cancelled = true; };
  }, [userId]); // deps array replaces the prevProps.userId !== check

  return data ? <div>{data.name}</div> : <p>Loading…</p>;
}

// Class component — setup and cleanup in separate methods
class WindowListener extends React.Component {
  componentDidMount() {
    window.addEventListener('resize', this.handleResize);
  }
  componentWillUnmount() {
    window.removeEventListener('resize', this.handleResize);
  }
}

// Function component — setup and cleanup colocated
function WindowListener() {
  useEffect(() => {
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);
}

// Class component
class RowItem extends React.Component {
  shouldComponentUpdate(nextProps) {
    return nextProps.name !== this.props.name
        || nextProps.active !== this.props.active;
    // returns true = DO re-render
  }
  render() {
    return <li className={this.props.active ? 'active' : ''}>{this.props.name}</li>;
  }
}

// Function component
const RowItem = React.memo(
  function RowItem({ name, active }) {
    return <li className={active ? 'active' : ''}>{name}</li>;
  },
  (prevProps, nextProps) =>
    prevProps.name === nextProps.name && prevProps.active === nextProps.active
    // returns true = SKIP re-render (opposite of shouldComponentUpdate!)
);

// Class component with getDerivedStateFromProps
class FilteredList extends React.Component {
  static getDerivedStateFromProps(props, state) {
    if (props.filter !== state.filter) {
      return {
        filteredItems: props.items.filter(i => i.category === props.filter),
        filter: props.filter,
      };
    }
    return null;
  }
  state = { filteredItems: [], filter: null };
  render() { return <ul>{this.state.filteredItems.map(renderItem)}</ul>; }
}

// Function component — just derive during render
function FilteredList({ items, filter }) {
  const filteredItems = useMemo(
    () => items.filter(i => i.category === filter),
    [items, filter]
  );
  return <ul>{filteredItems.map(renderItem)}</ul>;
}

// No prevProps/prevState in hooks — use useRef
function UserCard({ userId }) {
  const prevUserIdRef = useRef(userId);

  useEffect(() => {
    if (prevUserIdRef.current !== userId) {
      analytics.track('user-changed', {
        from: prevUserIdRef.current,
        to: userId,
      });
    }
    prevUserIdRef.current = userId; // update AFTER logging
  }, [userId]);

  return <UserDetails userId={userId} />;
}

// Class: this.state is always current — no stale closure
class Timer extends React.Component {
  tick = () => {
    console.log('count:', this.state.count); // always fresh
  };
  componentDidMount() {
    this.id = setInterval(this.tick, 1000);
  }
}

// Function: closure captures count at render time
function Timer() {
  const [count, setCount] = useState(0);

  // BUG: empty deps → count always 0 in the closure
  useEffect(() => {
    const id = setInterval(() => console.log('count:', count), 1000);
    return () => clearInterval(id);
  }, []);

  // Fix: use functional updater — avoid reading count inside the effect
  useEffect(() => {
    const id = setInterval(() => setCount((c) => c + 1), 1000);
    return () => clearInterval(id);
  }, []); // safe — effect never reads count
}

// Class component
class ScrollList extends React.Component {
  getSnapshotBeforeUpdate(prevProps) {
    if (prevProps.items.length < this.props.items.length) {
      return this.listRef.scrollHeight - this.listRef.scrollTop;
    }
    return null;
  }
  componentDidUpdate(prevProps, prevState, snapshot) {
    if (snapshot !== null) {
      this.listRef.scrollTop = this.listRef.scrollHeight - snapshot;
    }
  }
}

// Function component approach
function ScrollList({ items }) {
  const listRef = useRef(null);
  const prevScrollHeight = useRef(null);

  // Capture before React changes the DOM
  if (listRef.current) {
    prevScrollHeight.current = listRef.current.scrollHeight;
  }

  useLayoutEffect(() => {
    const list = listRef.current;
    if (prevScrollHeight.current !== null) {
      list.scrollTop = list.scrollHeight - prevScrollHeight.current;
    }
  });

  return <ul ref={listRef}>{items.map(i => <li key={i.id}>{i.text}</li>)}</ul>;
}

// Class component — concerns mixed in one method
class Dashboard extends React.Component {
  componentDidMount() {
    // analytics
    analytics.track('page_view', { page: this.props.page });
    // subscription
    this.sub = store.subscribe(this.handleChange);
    // timer
    this.timer = setInterval(this.refresh, 5000);
  }
  componentWillUnmount() {
    this.sub.unsubscribe();
    clearInterval(this.timer);
  }
}

// Function component — each concern in its own effect
function Dashboard({ page }) {
  // 1. Analytics
  useEffect(() => {
    analytics.track('page_view', { page });
  }, [page]);

  // 2. Store subscription
  useEffect(() => {
    const sub = store.subscribe(handleChange);
    return () => sub.unsubscribe();
  }, []);

  // 3. Polling timer
  useEffect(() => {
    const timer = setInterval(refresh, 5000);
    return () => clearInterval(timer);
  }, []);
}

// useLayoutEffect — synchronous, before browser paints
// Use for: measuring DOM, scroll restoration, tooltip positioning
useLayoutEffect(() => {
  const { height } = ref.current.getBoundingClientRect();
  setHeight(height); // state update batched before paint — no flicker
}, [content]);

// useEffect — asynchronous, after browser paints
// Use for: data fetching, subscriptions, logging
useEffect(() => {
  fetch('/api/data').then(r => r.json()).then(setData);
}, []);

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true };
  }

  componentDidCatch(error, info) {
    logErrorToService(error, info.componentStack);
  }

  render() {
    if (this.state.hasError) return <h1>Something went wrong.</h1>;
    return this.props.children;
  }
}

// Usage — wraps function components
function App() {
  return (
    <ErrorBoundary>
      <MyFunctionComponent />
    </ErrorBoundary>
  );
}

// Testing a hook-based component — effects fire automatically
import { render, screen, waitFor } from '@testing-library/react';

test('loads user on mount', async () => {
  fetchMock.mockResolvedValueOnce({ name: 'Alice' });

  render(<UserProfile userId={1} />);

  // Effect fires, component shows loading initially
  expect(screen.getByText(/loading/i)).toBeInTheDocument();

  // Wait for effect to resolve
  await waitFor(() => {
    expect(screen.getByText('Alice')).toBeInTheDocument();
  });
});

// Testing cleanup
test('unsubscribes on unmount', () => {
  const unsubscribe = jest.fn();
  storeMock.subscribe.mockReturnValue({ unsubscribe });

  const { unmount } = render(<Dashboard />);
  unmount();

  expect(unsubscribe).toHaveBeenCalledTimes(1);
});
